const input = $input.first().json;
const nome = input.nome || 'chefe';
const chatId = input.chatId || '';
const canal = input.canal || 'unknown';
const source = input.source || '';
const whatsapp_id = input.whatsapp_id || '';

const prompt = `Você é o Tarefildo Silva das Pendências. Bot assistente de tarefas.
Personalidade: funcionário raiz, engraçado, sarcástico, motivador.
Locuções: "bora resolver", "já era pra ontem", "confia no Tarefildo", "menos bagunça".

Um novo usuário se cadastrou:
- Nome: ${nome}
- Canal: ${canal}

Dê boas-vindas de forma calorosa e descontraída. Convide a adicionar tarefas.
Máximo 3 frases. Use 2-3 emojis. Responda APENAS em texto puro, sem JSON.`;

const text = `novo_usuario: ${nome}, canal: ${canal}`;

return [{ json: {
  prompt,
  text,
  chatId,
  nome,
  source,
  whatsapp_id,
  intent: 'novo_cadastro',
  ...input
} }];

const response = $input.first().json;
const prep = $('Prep-Nova-Conta').first().json;

const fallback = `Beleza ${prep.nome}, bem-vindo ao Tarefildo! ☕ Bora organizar suas tarefas?`;

if (response.error || !response.choices) {
  console.warn(`[FALLBACK-NOVA-CONTA] DeepSeek falhou`);
  return [{ json: {
    chatId: prep.chatId,
    mensagem: fallback,
    source: prep.source,
    whatsapp_id: prep.whatsapp_id,
    fallback_used: true
  } }];
}

let mensagem = response.choices[0].message.content.trim();
mensagem = mensagem.replace(/```json/gi, '').replace(/```/g, '').trim();

return [{ json: {
  chatId: prep.chatId,
  mensagem: mensagem,
  source: prep.source,
  whatsapp_id: prep.whatsapp_id,
  fallback_used: false
} }];

const input = $input.first().json;
const nome = input.nome || 'chefe';
const chatId = input.chatId || '';
const source = input.source || '';
const whatsapp_id = input.whatsapp_id || '';
const titulo = input.titulo || input.dados?.titulo || '';
const data = input.data || input.dados?.data || '';
const status = input.status_tarefa || 'PENDENTE';

const dataFormatada = data ? new Date(data).toLocaleDateString('pt-BR') : null;

const prompt = `Você é Tarefildo Silva das Pendências. Bot assistente.
Uma tarefa foi anotada:
- Título: "${titulo}"
- Status: ${status}
- Data: ${dataFormatada || 'não definida'}
- Usuário: ${nome}

Confirme naturalmente que a tarefa foi anotada.
${status === 'AGUARDANDO_DATA' ? 'Peça pela data de forma descontraída.' : 'Confirme a data.  '}
Máximo 2 frases. Use 1-2 emojis. Responda apenas em texto puro.`;

const text = `tarefa: ${titulo}, status: ${status}`;

return [{ json: {
  prompt,
  text,
  chatId,
  nome,
  source,
  whatsapp_id,
  intent: 'adicionar_tarefa',
  titulo,
  status,
  ...input
} }];

const response = $input.first().json;
const prep = $('Prep-Adicionar-Tarefa').first().json;
const status = prep.status || 'PENDENTE';
const titulo = prep.titulo || '';

const fallback = status === 'AGUARDANDO_DATA'
  ? `Anotado, ${prep.nome}: '${titulo}'. Me fala a data 👀`
  : `${prep.nome}, '${titulo}' anotado! Confia no Tarefildo ☕`;

if (response.error || !response.choices) {
  console.warn(`[FALLBACK-ADICIONAR-TAREFA] DeepSeek falhou`);
  return [{ json: {
    chatId: prep.chatId,
    mensagem: fallback,
    source: prep.source,
    whatsapp_id: prep.whatsapp_id,
    fallback_used: true
  } }];
}

let mensagem = response.choices[0].message.content.trim();
mensagem = mensagem.replace(/```json/gi, '').replace(/```/g, '').trim();

return [{ json: {
  chatId: prep.chatId,
  mensagem: mensagem,
  source: prep.source,
  whatsapp_id: prep.whatsapp_id,
  fallback_used: false
} }];

